// Transform raw Binance klines + attach coin context
const rawKlines = $input.first().json;
const coin = $('Loop Coins').item.json;

if (!Array.isArray(rawKlines) || rawKlines.length < 50) {
  return [{ json: { skip: true, symbol: coin.symbol, reason: 'insufficient_data' } }];
}

const candles = rawKlines.map(c => ({
  timestamp: new Date(c[0]).toISOString(),
  open:   parseFloat(c[1]),
  high:   parseFloat(c[2]),
  low:    parseFloat(c[3]),
  close:  parseFloat(c[4]),
  volume: parseFloat(c[5])
}));

// Validate — skip candles with zero/NaN prices
const valid = candles.every(c => c.close > 0 && isFinite(c.close));
if (!valid) {
  return [{ json: { skip: true, symbol: coin.symbol, reason: 'invalid_candles' } }];
}

return [{ json: { candles, symbol: coin.symbol, display_name: coin.display_name, skip: false } }];

const d = $input.first().json;

if (d.skip) {
  return [{ json: { is_signal: false, symbol: d.symbol } }];
}

const candles = d.candles;
const closes  = candles.map(c => c.close);
const highs   = candles.map(c => c.high);
const lows    = candles.map(c => c.low);
const volumes = candles.map(c => c.volume);
const n = closes.length;

// ATR (Wilder's smoothing)
function calcATR(highs, lows, closes, period) {
  const tr = [];
  for (let i = 1; i < closes.length; i++) {
    tr.push(Math.max(
      highs[i] - lows[i],
      Math.abs(highs[i] - closes[i-1]),
      Math.abs(lows[i] - closes[i-1])
    ));
  }
  let atr = tr.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < tr.length; i++) {
    atr = (atr * (period - 1) + tr[i]) / period;
  }
  return atr;
}

const atr14 = calcATR(highs, lows, closes, 14);
const atr7  = calcATR(highs, lows, closes, 7);

// Highest High / Lowest Low over last 30 candles (excluding current)
const hh30 = Math.max(...highs.slice(-31, -1));
const ll30 = Math.min(...lows.slice(-31, -1));

// Rate of Change (12 periods)
const roc12 = (closes[n-1] - closes[n-13]) / closes[n-13];

// Volume SMA 20
const volSma20 = volumes.slice(-20).reduce((a, b) => a + b, 0) / 20;
const latestVol = volumes[n-1];
const volumeRatio = latestVol / volSma20;

return [{ json: {
  symbol: d.symbol,
  display_name: d.display_name,
  latest_close: closes[n-1],
  latest_volume: latestVol,
  atr14, atr7, hh30, ll30, roc12,
  vol_sma20: volSma20,
  volume_ratio: volumeRatio
}}];

const d = $input.first().json;
const { latest_close, latest_volume, hh30, ll30, roc12, vol_sma20, volume_ratio, atr14, atr7, symbol, display_name } = d;

let signal = null;

// LONG breakout
if (latest_close > hh30 && roc12 > 0.02 && latest_volume > vol_sma20) {
  signal = {
    is_signal: true,
    direction: 'long',
    signal_type: 'breakout_high',
    coin: display_name,
    symbol,
    current_price: latest_close,
    breakout_level: Math.round(hh30 * 1e8) / 1e8,
    momentum_roc12: Math.round(roc12 * 10000) / 10000,
    volume_ratio: Math.round(volume_ratio * 100) / 100,
    atr14: Math.round(atr14 * 1e8) / 1e8,
    atr7: Math.round(atr7 * 1e8) / 1e8,
    timestamp: new Date().toISOString()
  };
}

// SHORT breakout
if (!signal && latest_close < ll30 && roc12 < -0.02 && latest_volume > vol_sma20) {
  signal = {
    is_signal: true,
    direction: 'short',
    signal_type: 'breakout_low',
    coin: display_name,
    symbol,
    current_price: latest_close,
    breakout_level: Math.round(ll30 * 1e8) / 1e8,
    momentum_roc12: Math.round(roc12 * 10000) / 10000,
    volume_ratio: Math.round(volume_ratio * 100) / 100,
    atr14: Math.round(atr14 * 1e8) / 1e8,
    atr7: Math.round(atr7 * 1e8) / 1e8,
    timestamp: new Date().toISOString()
  };
}

if (!signal) {
  signal = { is_signal: false, symbol };
}

return [{ json: signal }];

const signal = $('Loop Analyst').item.json;
const portfolio = $input.first().json;

const message = JSON.stringify({
  signal: {
    id: signal.id,
    coin: signal.coin,
    direction: signal.direction,
    signal_type: signal.signal_type,
    ...signal.signal_data
  },
  portfolio: {
    available_capital: parseFloat(portfolio.available_capital),
    total_value: parseFloat(portfolio.total_value),
    open_positions_count: parseInt(portfolio.open_positions_count)
  },
  mindsdb_prediction: null
});

return [{ json: { message, signal_id: signal.id } }];

const response = $input.first().json;
const signalId = $('Prepare Analyst Input').item.json.signal_id;

// Extract agent response content
const content = response.message?.content ||
                response.content ||
                response.response ||
                JSON.stringify(response);

let tradeCard;
try {
  // Try direct parse
  const trimmed = content.trim();
  if (trimmed.startsWith('{')) {
    tradeCard = JSON.parse(trimmed);
  } else {
    // Extract from text
    const match = trimmed.match(/```(?:json)?\s*([\s\S]+?)```/);
    if (match) {
      tradeCard = JSON.parse(match[1].trim());
    } else {
      const start = trimmed.indexOf('{');
      const end = trimmed.lastIndexOf('}');
      tradeCard = JSON.parse(trimmed.slice(start, end + 1));
    }
  }
} catch (e) {
  throw new Error(`Analyst response parse error for ${signalId}: ${e.message}`);
}

if (tradeCard.error) {
  throw new Error(`Analyst error for ${signalId}: ${tradeCard.error}`);
}

return [{ json: { signalId, tradeCard } }];

const signal = $('Loop Risk').item.json;
const rows = $input.all().map(r => r.json);

// Extract portfolio and risk config from first row
const r0 = rows[0];
const portfolio = {
  available_capital: parseFloat(r0.available_capital),
  total_value: parseFloat(r0.total_value),
  today_pnl_usdt: parseFloat(r0.today_pnl_usdt),
  month_pnl_usdt: parseFloat(r0.month_pnl_usdt),
  month_start_capital: parseFloat(r0.month_start_capital),
  consecutive_losses: parseInt(r0.consecutive_losses),
  last_loss_at: r0.last_loss_at,
  system_active: r0.system_active
};

const risk_config = {
  max_risk_per_trade_pct: parseFloat(r0.max_risk_per_trade_pct),
  max_open_positions: parseInt(r0.max_open_positions),
  max_daily_loss_pct: parseFloat(r0.max_daily_loss_pct),
  max_monthly_drawdown_pct: parseFloat(r0.max_monthly_drawdown_pct),
  max_position_size_pct: parseFloat(r0.max_position_size_pct),
  min_capital: parseFloat(r0.min_capital),
  cooldown_after_loss_hours: parseInt(r0.cooldown_after_loss_hours),
  max_consecutive_losses_pause: parseInt(r0.max_consecutive_losses_pause),
  signal_expiry_minutes: parseInt(r0.signal_expiry_minutes)
};

const open_trades = rows
  .filter(r => r.trade_id)
  .map(r => ({
    id: r.trade_id, coin: r.trade_coin,
    direction: r.trade_direction,
    entry_price: parseFloat(r.trade_entry),
    position_size_usdt: parseFloat(r.trade_size),
    current_stop: parseFloat(r.trade_stop)
  }));

const tradeCard = signal.trade_card || {};

const message = JSON.stringify({
  trade_card: {
    signal_id: signal.id,
    coin: signal.coin,
    direction: signal.direction,
    entry_price: parseFloat(signal.entry_price),
    stop_loss: parseFloat(signal.stop_loss),
    position_size_usdt: parseFloat(signal.position_size_usdt),
    risk_amount_usdt: parseFloat(signal.risk_amount_usdt),
    confidence_score: parseFloat(signal.confidence_score),
    timestamp: signal.created_at,
    ...tradeCard
  },
  portfolio,
  open_trades,
  recent_trades: [],
  risk_config
});

return [{ json: { message, signal_id: signal.id } }];

const response = $input.first().json;
const signalId = $('Prepare Risk Input').item.json.signal_id;

const content = response.message?.content ||
                response.content ||
                response.response ||
                JSON.stringify(response);

let decision;
try {
  const trimmed = content.trim();
  if (trimmed.startsWith('{')) {
    decision = JSON.parse(trimmed);
  } else {
    const match = trimmed.match(/```(?:json)?\s*([\s\S]+?)```/);
    if (match) {
      decision = JSON.parse(match[1].trim());
    } else {
      const start = trimmed.indexOf('{');
      const end = trimmed.lastIndexOf('}');
      decision = JSON.parse(trimmed.slice(start, end + 1));
    }
  }
} catch (e) {
  // Fail safe: reject on parse error
  decision = {
    signal_id: signalId,
    decision: 'rejected',
    checks: [],
    rejection_reason: `Parse error: ${e.message}`,
    system_stop: false,
    system_stop_reason: null
  };
}

return [{ json: { signalId, decision } }];
